// Zebra Health EDS Tracker — data.js v2
const { useState, useRef, useCallback } = React;

// ─── LOCAL STORAGE LAYER ──────────────────────────────────────
// All user data stays on this device. Nothing is sent to any server.
// Data survives app restarts and phone reboots.
// Key prefix prevents collisions with other apps.

const STORE_KEY = "zheds_v1";

function saveAll(data) {
  try {
    localStorage.setItem(STORE_KEY, JSON.stringify(data));
  } catch(e) {
    console.warn("Zebra Health: storage write failed", e);
  }
}

function loadAll() {
  try {
    var raw = localStorage.getItem(STORE_KEY);
    return raw ? JSON.parse(raw) : null;
  } catch(e) {
    console.warn("Zebra Health: storage read failed", e);
    return null;
  }
}

function clearAll() {
  try { localStorage.removeItem(STORE_KEY); } catch(e) {}
}

// ─── EXPORT UTILITIES ─────────────────────────────────────────

function toCSV(rows, headers) {
  var lines = [headers.join(",")];
  rows.forEach(function(row) {
    lines.push(headers.map(function(h) {
      var val = row[h] !== undefined ? String(row[h]) : "";
      val = val.replace(/"/g, '""');
      return val.includes(",") || val.includes('"') || val.includes("\n")
        ? '"' + val + '"' : val;
    }).join(","));
  });
  return lines.join("\n");
}

function downloadCSV(csv, filename) {
  var blob = new Blob([csv], {type:"text/csv"});
  var url = URL.createObjectURL(blob);
  var a = document.createElement("a");
  a.href = url; a.download = filename;
  document.body.appendChild(a); a.click();
  document.body.removeChild(a); URL.revokeObjectURL(url);
}

function exportAllData(state) {
  var today = new Date().toISOString().split("T")[0];
  var sections = [];

  if (state.symptoms && state.symptoms.length > 0) {
    sections.push("=== SYMPTOM LOG ===");
    sections.push(toCSV(state.symptoms, ["date","condition","symptom","severity","notes","triggers","relief"]));
  }
  if (state.vitalLog && state.vitalLog.length > 0) {
    sections.push("\n=== VITALS LOG ===");
    sections.push(toCSV(state.vitalLog, ["date","time","hr","bp_s","bp_d","o2","temp","energy","notes"]));
  }
  if (state.meds && state.meds.length > 0) {
    sections.push("\n=== MEDICATIONS ===");
    sections.push(toCSV(state.meds, ["name","dose","freq","cat","refill","notes"]));
  }
  if (state.appts && state.appts.length > 0) {
    sections.push("\n=== APPOINTMENTS ===");
    sections.push(toCSV(state.appts, ["type","date","time","notes"]));
  }
  if (state.labs && state.labs.length > 0) {
    sections.push("\n=== LAB RESULTS ===");
    sections.push(toCSV(state.labs, ["test","value","date","notes"]));
  }
  if (state.joints && state.joints.length > 0) {
    sections.push("\n=== JOINT LOG ===");
    sections.push(toCSV(state.joints, ["joint","severity","time","notes"]));
  }
  if (state.lcRecovery && state.lcRecovery.length > 0) {
    sections.push("\n=== ENERGY/PACING LOG ===");
    sections.push(toCSV(state.lcRecovery, ["date","pct","milestone","notes"]));
  }

  var csv = sections.join("\n");
  downloadCSV(csv, "zebra-health-export-" + today + ".csv");
}

function exportHealthSummary(state) {
  var today = new Date().toLocaleDateString("en-US", {year:"numeric",month:"long",day:"numeric"});
  var meds = (state.meds||[]).map(function(m){return "• "+m.name+" "+m.dose+" — "+m.freq;}).join("\n");
  var appts = (state.appts||[]).map(function(a){return "• "+a.type+" — "+a.date+(a.time?" at "+a.time:"");}).join("\n");
  var labs = (state.labs||[]).map(function(l){return "• "+l.test+": "+l.value+" ("+l.date+")";}).join("\n");
  var html = [
    "<html><head><title>Zebra Health Summary</title>",
    "<style>body{font-family:Arial,sans-serif;max-width:800px;margin:40px auto;padding:20px;color:#111;}",
    "h1{color:#6b21a8;border-bottom:2px solid #6b21a8;padding-bottom:8px;}",
    "h2{color:#4c1d95;margin-top:28px;}",
    "p,li{line-height:1.8;} ul{margin:8px 0;} .note{color:#666;font-size:13px;}",
    ".header{background:#f5f3ff;border-left:4px solid #8850f0;padding:12px 16px;margin-bottom:24px;}",
    "</style></head><body>",
    "<h1>✦ Zebra Health — Patient Summary</h1>",
    '<div class="header"><strong>Exported:</strong> '+today+'<br>',
    "<strong>App:</strong> Zebra Health EDS/POTS/MCAS Tracker<br>",
    '<p class="note">This summary was generated from data stored locally on your device.</p></div>',
    "<h2>Current Medications</h2>",
    meds ? "<pre>"+meds+"</pre>" : "<p>No medications recorded.</p>",
    "<h2>Upcoming Appointments</h2>",
    appts ? "<pre>"+appts+"</pre>" : "<p>No appointments recorded.</p>",
    "<h2>Recent Lab Results</h2>",
    labs ? "<pre>"+labs+"</pre>" : "<p>No lab results recorded.</p>",
    "<h2>Current Conditions Tracked</h2>",
    "<ul><li>Ehlers-Danlos Syndrome (EDS)</li><li>Postural Orthostatic Tachycardia Syndrome (POTS)</li>",
    "<li>Mast Cell Activation Syndrome (MCAS)</li></ul>",
    "<p class='note'>Generated by Zebra Health — data stored on device only.</p>",
    "</body></html>"
  ].join("");

  var win = window.open("","_blank");
  if (win) { win.document.write(html); win.document.close(); win.print(); }
}



