  histamine_liberators:{label:"Histamine Liberators",icon:"🟠",color:"#f59e0b",note:"Low in histamine but trigger mast cells to release it. Highly individual — some people tolerate these well.",subcats:{"Fruits":["Strawberries","Raspberries","Blackberries","Pineapple","Papaya","Mango","Kiwi","Banana (ripe)","All citrus (lemon, lime, orange, grapefruit)","Guava","Plums","Prunes","Dates","All dried fruits"],"Vegetables":["Tomatoes (all forms)","Spinach","Eggplant","Avocado","Pumpkin","Most legumes (beans, lentils)","Chickpeas","All soy products"],"Nuts & Seeds":["Peanuts","Walnuts","Cashews","Almonds","Brazil nuts","Sunflower seeds"],"Shellfish":["Shrimp","Lobster","Crab","Crayfish","Clams","Mussels","Oysters","Scallops"],"Other":["Egg whites (yolks usually tolerated)","Chocolate and cocoa","Alcohol (also high histamine)","Artificial food colors — Red 40, Yellow 5, Blue 1","Sodium benzoate","Sulfites","Nitrates and nitrites","MSG and glutamates"]}},
